// TestNovelResolveHelpWires smoke-tests that the resolve command
// resolves at runtime and renders --help without error. Catches wiring
// regressions (missing AddCommand, panicking RunE on --help, etc.) before
// review. Always runs — do not delete this test when filling in real cases.
func TestNovelResolveHelpWires(t *testing.T) {
	cmd := RootCmd()
	cmd.SetArgs([]string{"resolve", "--help"})
	cmd.SetOut(io.Discard)
	cmd.SetErr(io.Discard)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("resolve --help error = %v (novel command not wired correctly?)", err)
	}
}

